using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpStdioServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool("fetch_api_data"), Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchApiDataAsync(
        IHttpClientFactory httpClientFactory,
        [Description("The API path to call (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpStdioServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt("summarize"), Description("Summarizes the provided text at a chosen detail level.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Detail level: brief, standard, or detailed.")] string detail = "standard")
    {
        var systemInstruction = detail.ToLowerInvariant() switch
        {
            "brief"    => "Produce a one-sentence summary.",
            "detailed" => "Produce a thorough, multi-paragraph summary preserving key details.",
            _          => "Produce a concise summary of a few sentences.",
        };

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{systemInstruction}\n\n{text}" },
            },
        ];
    }
}

