using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpStdioServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Summarizes the provided text at a chosen detail level.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Detail level: brief, standard, or detailed.")] string detail = "standard")
    {
        var systemInstruction = detail.ToLowerInvariant() switch
        {
            "brief"    => "Produce a one-sentence summary.",
            "detailed" => "Produce a thorough, multi-paragraph summary preserving key details.",
            _          => "Produce a concise summary of a few sentences.",
        };

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{systemInstruction}\n\n{text}" },
            },
        ];
    }
}

